import getReadingTime from 'reading-time';
import { toString } from 'mdast-util-to-string';
import type { RehypePlugin, RemarkPlugin } from '@astrojs/markdown-remark';

export const readingTimeRemarkPlugin: RemarkPlugin = () => {
  return function (tree, file) {
    const textOnPage = toString(tree);
    const readingTime = Math.ceil(getReadingTime(textOnPage).minutes);

    if (typeof file?.data?.astro?.frontmatter !== 'undefined') {
      file.data.astro.frontmatter.readingTime = readingTime;
    }
  };
};

export const responsiveTablesRehypePlugin: RehypePlugin = () => {
  return function (tree) {
    if (!tree.children) return;

    for (let i = 0; i < tree.children.length; i++) {
      const child = tree.children[i];

      if (child.type === 'element' && child.tagName === 'table') {
        tree.children[i] = {
          type: 'element',
          tagName: 'div',
          properties: {
            style: 'overflow:auto',
          },
          children: [child],
        };

        i++;
      }
    }
  };
};

export function hasNonPrerenderedRoute(
	routes: Array<Pick<RouteData, 'type' | 'origin' | 'prerender'>>,
	options?: { includeEndpoints?: boolean; includeExternal?: boolean },
): boolean;
export function hasNonPrerenderedRoute(
	routes: Array<Pick<IntegrationResolvedRoute, 'type' | 'origin' | 'isPrerendered'>>,
	options?: { includeEndpoints?: boolean; includeExternal?: boolean },
): boolean;
export function hasNonPrerenderedRoute(
	routes: Array<
		| Pick<RouteData, 'type' | 'origin' | 'prerender'>
		| Pick<IntegrationResolvedRoute, 'type' | 'origin' | 'isPrerendered'>
	>,
	options?: { includeEndpoints?: boolean; includeExternal?: boolean },
): boolean {
	const includeEndpoints = options?.includeEndpoints ?? true;
	const includeExternal = options?.includeExternal ?? false;
	const routeTypes: ReadonlyArray<string> = includeEndpoints ? ['page', 'endpoint'] : ['page'];
	const origins: ReadonlyArray<string> = includeExternal ? ['project', 'external'] : ['project'];

	return routes.some((route) => {
		const isPrerendered = 'isPrerendered' in route ? route.isPrerendered : route.prerender;
		return routeTypes.includes(route.type) && origins.includes(route.origin) && !isPrerendered;
	});
}

interface AstroQuery {
	astro?: boolean;
	src?: boolean;
	type?: 'script' | 'template' | 'style' | 'custom';
	index?: number;
	lang?: string;
	raw?: boolean;
	inline?: boolean;
}

interface ParsedRequestResult {
	filename: string;
	query: AstroQuery;
}

// Parses an id to check if it's an Astro request.
// CSS is imported like `import '/src/pages/index.astro?astro&type=style&index=0&lang.css';
// This parses those ids and returns an object representing what it found.
export function parseAstroRequest(id: string): ParsedRequestResult {
	const [filename, rawQuery] = id.split(`?`, 2);
	const query = Object.fromEntries(new URLSearchParams(rawQuery).entries()) as AstroQuery;
	if (query.astro != null) {
		query.astro = true;
	}
	if (query.src != null) {
		query.src = true;
	}
	if (query.index != null) {
		query.index = Number(query.index);
	}
	if (query.raw != null) {
		query.raw = true;
	}
	if (query.inline != null) {
		query.inline = true;
	}
	return {
		filename,
		query,
	};
}

export const baseSchema = z.object({
	type: z.literal('base').optional().default('base'),
	i18nReady: z.boolean().default(false),
	githubURL: z.url().optional(),
	hasREADME: z.boolean().optional(),
	// Extends Starlight’s default `hero` schema with custom fields.
	hero: z
		.object({
			facepile: z.object({
				tagline: z.string(),
				linkText: z.string(),
				link: z.string(),
			}),
		})
		.optional(),
});

// Third-party guide schemas (deploy, backend, cms, media)
export const deploySchema = baseSchema.extend({
	type: z.literal('deploy'),
	logo: z.enum(logoKeys),
	supports: z.array(z.enum(['static', 'ssr'])),
});

export const backendSchema = baseSchema.extend({
	type: z.literal('backend'),
	stub: z.boolean().default(false),
	logo: z.enum(logoKeys),
});

export const cmsSchema = baseSchema.extend({
	type: z.literal('cms'),
	stub: z.boolean().default(false),
	logo: z.enum(logoKeys),
	featuredListing: z
		.object({
			tagline: z.string().min(30).max(160),
		})
		.optional(),
});

export const mediaSchema = baseSchema.extend({
	type: z.literal('media'),
	stub: z.boolean().default(false),
	logo: z.enum(logoKeys),
});

