// https://github.com/francoischalifour/medium-zoom
import config from 'virtual:config'

interface Props {
  selector?: string
  background?: string
}

const { selector = config.integ.mediumZoom.selector, background = 'hsl(var(--background) / 0.8)' } =
  Astro.props
---

<script is:inline src={`${config.npmCDN}/medium-zoom/dist/pure/medium-zoom.min.umd.js`}></script>
<script is:inline define:vars={{ selector, background }}>
  mediumZoom(selector, { background })
</script>
<style is:global>
  .medium-zoom-overlay {
    position: fixed;
    top: 0;
    right: 0;
    bottom: 0;
    left: 0;
    opacity: 0;
    transition: opacity 0.3s;
    will-change: opacity;
  }
  .medium-zoom--opened .medium-zoom-overlay {
    cursor: zoom-out;
    opacity: 1;
    z-index: 999;
  }
  .medium-zoom-image {
    cursor: zoom-in;
    transition: transform 0.3s cubic-bezier(0.2, 0, 0.2, 1);
  }
  .medium-zoom-image--hidden {
    visibility: hidden;
  }
  .medium-zoom-image--opened {
    position: relative;
    cursor: zoom-out;
    will-change: transform;
    z-index: 999;
  }
</style>

