import { extname } from 'node:path'
import { z } from 'astro/zod'

const faviconTypeMap = {
  '.ico': 'image/x-icon',
  '.gif': 'image/gif',
  '.jpeg': 'image/jpeg',
  '.jpg': 'image/jpeg',
  '.png': 'image/png',
  '.svg': 'image/svg+xml'
}

export const FaviconSchema = () =>
  z
    .string()
    .default('/favicon/favicon.svg')
    .transform((favicon, ctx) => {
      // favicon can be absolute or relative url
      const { pathname } = new URL(favicon, 'https://example.com')
      const ext = extname(pathname).toLowerCase()
      if (!isFaviconExt(ext)) {
        ctx.issues.push({
          code: 'custom',
          message: 'favicon must be a .ico, .gif, .jpg, .png, or .svg file',
          input: favicon
        })

        return z.NEVER
      }

      return {
        href: favicon,
        type: faviconTypeMap[ext]
      }
    })
    .describe(
      'The default favicon for your site which should be a path to an image in the `public/` directory.'
    )

function isFaviconExt(ext: string): ext is keyof typeof faviconTypeMap {
  return ext in faviconTypeMap
}

import type { Node, Root } from 'mdast'
import type { Plugin } from 'unified'
import { visit } from 'unist-util-visit'

// Cannot use '../utils' for plugin absolute path
import mdastToString from '../utils/mdast-util-to-string'
import getReadingTime from '../utils/reading-time'

export const remarkAddZoomable: Plugin<[{ className?: string }], Root> =
  ({ className = 'zoomable' }) =>
  (tree) => {
    visit(tree, 'image', (node: Node) => {
      node.data = { hProperties: { class: className } }
    })
  }

export const remarkReadingTime: Plugin<[], Root> =
  () =>
  (tree, { data }) => {
    const textOnPage = mdastToString(tree)
    const readingTime = getReadingTime(textOnPage)
    // readingTime.text will give us minutes read as a friendly string,
    // i.e. "3 min"
    if (data.astro?.frontmatter) {
      data.astro.frontmatter.minutesRead = readingTime.text
      data.astro.frontmatter.words = readingTime.words
    }
  }

import type { MarkdownHeading } from 'astro'

export interface TocItem extends MarkdownHeading {
  subheadings: TocItem[]
}

export function generateToc(headings: readonly MarkdownHeading[]): TocItem[] {
  const root: TocItem = { depth: 0, slug: 'root', text: 'Root', subheadings: [] }
  const stack: TocItem[] = [root]

  headings.forEach((h) => {
    const heading: TocItem = { ...h, subheadings: [] }
    // Find the correct parent in the stack.
    // The parent is the last item on the stack with a depth less than the current heading.
    while (stack[stack.length - 1].depth >= heading.depth) {
      stack.pop()
    }
    // Add the new heading as a child of the correct parent.
    stack[stack.length - 1].subheadings.push(heading)
    // Push the new heading onto the stack, making it the current deepest heading.
    stack.push(heading)
  })
  return root.subheadings
}

