import { Icon } from "astro-icon/components";
---

<div
  id="scroll-down-indicator"
  class="scroll-down-indicator"
  onclick="document.getElementById('main-grid')?.scrollIntoView({ behavior: 'smooth' })"
>
  <Icon name="material-symbols:keyboard-arrow-down-rounded" class="scroll-down-icon" />
</div>

<script is:inline>
  (function () {
    // 防止重复初始化（Swup 页面切换时可能重复执行）
    if (window.__scrollDownIndicatorInit) return;
    window.__scrollDownIndicatorInit = true;

    function updateVisibility() {
      var indicator = document.getElementById("scroll-down-indicator");
      if (!indicator) return;
      var scrollTop = window.pageYOffset || document.documentElement.scrollTop;
      if (scrollTop > 100) {
        indicator.classList.add("hide");
      } else {
        indicator.classList.remove("hide");
      }
    }

    window.addEventListener("scroll", updateVisibility, { passive: true });
    updateVisibility();
  })();
</script>

// Sidebar handling functionality
export const initSidebar = () => {
  const sidebarToggle = document.getElementById("sidebar-toggle")
  const sidebar = document.querySelector(".sidebar")
  const mainContent = document.querySelector(".main-content")
  const overlay = document.querySelector(".sidebar-overlay")

  const toggleSidebar = () => {
    if (window.innerWidth <= 1200) {
      // Mobile: Show/hide sidebar with overlay
      sidebar?.classList.toggle("open")
      overlay?.classList.toggle("show")
    } else {
      // Desktop: Collapse/expand sidebar and adjust main content
      sidebar?.classList.toggle("collapsed")
      mainContent?.classList.toggle("expanded")
    }
  }

  // Event listeners
  sidebarToggle?.addEventListener("click", toggleSidebar)
  overlay?.addEventListener("click", toggleSidebar)

  // Reset sidebar state on window resize
  window.addEventListener("resize", () => {
    if (window.innerWidth > 1200) {
      overlay?.classList.remove("show")
      sidebar?.classList.remove("open")
    }
  })
}

import { z } from 'astro/zod'

import { IconSchema } from './icon'

const LinksSchema = z
  .object({ icon: IconSchema(), label: z.string().min(1), href: z.string() })
  .array()
  .optional()

export const SocialLinksSchema = () =>
  // Add a more specific error message to help people migrate from the old object syntax.
  // TODO: remove once most people have updated to v0.33 or higher (e.g. when releasing Starlight v1)
  z.preprocess((value, ctx) => {
    if (value && typeof value === 'object' && !Array.isArray(value)) {
      ctx.issues.push({
        code: 'custom',
        message:
          'Theme v4.1.5 changed the `social` configuration syntax. Please specify an array of link items instead of an object.',
        input: value
      })
    }
    return value
  }, LinksSchema) as unknown as typeof LinksSchema

